const W=Math.min(innerWidth,480),H=innerHeight;class S extends Phaser.Scene{create(){this.add.rectangle(W/2,H/2,W,H,0x101018);this.p=this.add.rectangle(40,H-40,18,18,0x8bd3ff);this.physics.add.existing(this.p);this.p.body.setCollideWorldBounds(true);this.p.body.setGravityY(500);this.goal=this.add.circle(W-30,30,12,0x72ff7a);this.platforms=this.physics.add.staticGroup();for(let i=0;i<8;i++){const x=70+i*45,y=(i%2?H*0.65:H*0.35);const r=this.add.rectangle(x,y,60,10,0xffffff,.2);this.physics.add.existing(r,true);this.platforms.add(r);}this.physics.add.collider(this.p,this.platforms);this.physics.add.overlap(this.p,this.goal,()=>this.win());this.input.on('pointerdown',()=>this.flip());this.c=this.input.keyboard.createCursorKeys();this.r=this.input.keyboard.addKey('R');}flip(){this.p.body.setGravityY(this.p.body.gravity.y>0?-500:500);}win(){if(this.done)return;this.done=true;this.add.text(W/2,H/2,'CLEAR!\nR',{align:'center'}).setOrigin(.5);}update(){if(this.r.isDown)this.scene.restart();if(this.done)return;if(this.c.left.isDown)this.p.body.setVelocityX(-170);else if(this.c.right.isDown)this.p.body.setVelocityX(170);else this.p.body.setVelocityX(0);if(Phaser.Input.Keyboard.JustDown(this.c.up))this.flip();}}new Phaser.Game({type:Phaser.AUTO,parent:'game',width:W,height:H,physics:{default:'arcade'},scene:[S]});